def run(*args): return subprocess.run(args,cwd=ROOT,text=True,capture_output=True)
def main():
    branch=run("git","branch","--show-current").stdout.strip()
    if branch != BRANCH: raise SystemExit(f"Expected branch {BRANCH!r}, found {branch!r}")
    status=run("git","status","--porcelain").stdout.strip()
    if status: raise SystemExit("Working tree must be clean before applying consolidation.\n"+status)
    for relative,payload in FILES:
        path=ROOT/relative; path.parent.mkdir(parents=True,exist_ok=True); path.write_bytes(base64.b64decode(payload)); print("Wrote",relative)
    print("\nConsolidation checkpoint applied. Legacy phase packages remain only for parity and rollback.")
if __name__=="__main__": main()
